function cycleFullCompact(sender,force); local state = not(compactmenuitem.Caption == 'Tắt Full Màn Hình'); if force~=nil then state = not force end; compactmenuitem.Caption = state and 'Mở Full Màn Hình' or 'Tắt Full Màn Hình'; getMainForm().Splitter1.Visible = state; getMainForm().Panel4.Visible = state; getMainForm().Panel5.Visible = state; end; function addCompactMenu(); if compactmenualreadyexists then return end; local parent = getMainForm().Menu.Items; compactmenuitem = createMenuItem(parent); parent.add(compactmenuitem); compactmenuitem.Caption = 'Tắt Full Màn Hình'; compactmenuitem.OnClick = cycleFullCompact; compactmenualreadyexists = 'yes'; end; addCompactMenu(); cycleFullCompact(nil,true)